VALUES
  ('social-worker-moex-07950', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某社會福利機構透過勸募活動募得 5 仟萬元捐款，依據公益勸募條例，該機構可以由勸募活動所得支應 辦理活動必要支出最高金額為：', '["4佰6拾萬元", "4佰7拾萬元", "4佰8拾萬元", "4佰9拾萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07951', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '臺灣已有一些福利機構使用「平衡計分卡」（balanced scorecard）作為績效評估工具，其主要的4個構面', '["財務構面", "策略構面", "顧客構面", "內部事業流程構面  ⑤外部競爭構面  ⑥學 習和成長構面"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07952', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會服務行銷的敘述，何者錯誤？', '["非營利組織並不追求利潤，但仍須有盈餘，以供組織未獲補助的方案所需", "關心的是人、理念、價值和服務", "利益的多寡與案主的支付有直接關係", "成效很難標準化，品質也很難保證，且不易衡量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07953', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在績效評估時設計以多方來源取得回饋，包括從督導、同事、部屬、案主還有被評估的當事人，此種評 估方式稱為：', '["全盤性評估", "回饋性評估", "360度評估", "整合性評估"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07954', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於身心障礙福利機構管理規定，下列何者錯誤？', '["住宿機構服務人數在七人以上，未滿四十人者，為小型機構", "住宿機構地板面積以服務人數計算，平均每人不得少於十六點五平方公尺", "住宿生活重建機構有關社會工作人員與受服務人數比例，以一比三十五遴用", "住宿機構每一寢室至多設四床"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07955', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何項理論與探討品質的重要性有關？', '["X理論", "Y理論", "Q理論", "Z理論"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07956', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '通常社會工作人員到機構或組織服務時，常會遭遇一套非正式的價值觀規範及信念，而其是可控制組織 內的個人與群體之間的互動關係，也可控制組織內個人和群體與組織外的個人間的互動關係，請問這是 何種現象？', '["組織文化", "組織環境", "組織結構", "組織生態"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07957', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '科學管理學派的創始者泰勒在其1911年出版的《科學管理的原則》述及提升組織每位員工效率之四項原 則，下列四項答案何者不正確？', '["動作科學化原則", "工人選用科學原則", "工作資格認定原則", "誠心合作及和諧原則"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07958', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '依R.A Skidmore所提的在決策過程中有四項決策陷阱，下列何者錯誤？', '["延宕（Procrastination）", "過分簡單化（Oversimplication）", "錯誤導致沮喪（Mistake bring discouragement）", "理性行為（Rational behavior）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07959', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '近些年來企業公司樂意與社會福利機構或非營利組織合作互動，其主要的原因之一乃是企業社會責任機 構（Corporate Social Responsibility, CSR）的日益盛行，下列對於CSR的描述何者不正確？', '["CSR強調公司除了追求股東利潤極大化外，同時要兼顧其他利害關係人的福利", "CSR是指企業透過符合道德的行為和促進經濟發展對當地社區社會作出貢獻", "CSR可以為公司帶來機會、創新和競爭優勢", "管理大師彼得聖吉稱CSR為企業要把產生利潤私有化且把產生成本社會化"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
